// Firebase Cloud Messaging service worker.
// This is separate from the Workbox SW (sw.js) generated by vite-plugin-pwa.
// Firebase registers this file automatically at /firebase-messaging-sw.js
// when the client calls getMessaging(). It must live in /public so it is
// served at the site root as-is (not bundled by Vite).
importScripts('https://www.gstatic.com/firebasejs/11.10.0/firebase-app-compat.js');
importScripts('https://www.gstatic.com/firebasejs/11.10.0/firebase-messaging-compat.js');

firebase.initializeApp({
  messagingSenderId: 'YOUR_MESSAGING_SENDER_ID',
});

const messaging = firebase.messaging();

// Handle background messages. When a push arrives and the app is closed/
// in the background, show a notification.
messaging.onBackgroundMessage((payload) => {
  const { title, body } = payload.notification ?? {};
  const { type, deepLink } = payload.data ?? {};

  const notificationOptions = {
    body: body ?? '',
    icon: '/icons/icon-192.png',
    badge: '/icons/icon-192.png',
    data: { deepLink: deepLink ?? '/', type: type ?? '' },
  };

  self.registration.showNotification(title ?? 'Kippa', notificationOptions);
});

// Handle notification click — focus or open the app at the deep link.
self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  const deepLink = event.notification.data?.deepLink ?? '/';

  event.waitUntil(
    clients.matchAll({ type: 'window', includeUncontrolled: true }).then((clientList) => {
      // Focus an existing window if one is open
      for (const client of clientList) {
        if (client.url.includes(self.location.origin) && 'focus' in client) {
          client.navigate(deepLink);
          return client.focus();
        }
      }
      // Otherwise open a new window
      if (clients.openWindow) {
        return clients.openWindow(deepLink);
      }
    }),
  );
});
